const items = [];
for (const it of $input.all()) {
  const d = it.json;
  const nome = d.name || '';
  const u = nome.toUpperCase();
  let tipo = 'GENERICO';
  if (u.includes('UBER') || u.includes('99') || u.includes('INDRIVE') || u.includes('APP MOBILIDADE') || u.includes('MOBILIDADE')) tipo = 'APP_MOBILIDADE';
  let status = 'Em curso';
  if (d.status === 'signed') status = 'Assinado';
  else if (d.status === 'refused' || d.status === 'rejected') status = 'Recusado';
  else if (d.status === 'expired') status = 'Expirado';
  items.push({ json: {
    zapsign_doc_id: d.token || d.open_id,
    nome_documento: nome,
    tipo_contrato: tipo,
    status,
    data_criacao: d.created_at,
    data_assinatura: d.last_update_at && status === 'Assinado' ? d.last_update_at : null,
    signers: d.signers || []
  } });
}
return items;

return $input.all().map(it => {
  const { signers, ...rest } = it.json;
  return { json: rest };
});

const original = $('Classificar contrato').all();
return $input.all().map(it => {
  const orig = original.find(o => o.json.zapsign_doc_id === it.json.zapsign_doc_id);
  return { json: { ...it.json, signers: orig?.json?.signers || [] } };
});

const statusMap = {
  nao_abriu: 'Nao abriu',
  abriu: 'Apenas visualizou',
  assinou: 'Assinou',
  recusou: 'Recusou',
  expirou: 'Expirou',
  cancelado: 'Cancelado',
  // legados em ingles, por seguranca:
  signed: 'Assinou',
  visualized: 'Apenas visualizou',
  refused: 'Recusou',
  rejected: 'Recusou',
  expired: 'Expirou'
};
const out = [];
for (const it of $input.all()) {
  const docId = it.json.zapsign_doc_id;
  for (const s of (it.json.signers || [])) {
    if (!s || !s.token) continue;
    out.push({ json: {
      zapsign_doc_id: docId,
      zapsign_signer_token: s.token,
      nome: s.name || '',
      email: s.email || '',
      telefone: s.phone_number || '',
      status: statusMap[s.status] || 'Nao abriu',
      data_assinatura: s.signed_at || null
    } });
  }
}
return out;
